"""Admin dashboard HTML/JS templates (LiMa)."""

ADMIN_HTML = '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>&#x674e;&#x9a6c;&#x7ba1;&#x7406;&#x9762;&#x677f;</title>\n<style>\n:root{color-scheme:dark;--bg:#07111f;--bg2:#0b1730;--panel:rgba(15,27,50,.82);--panel2:rgba(18,35,67,.94);--line:rgba(145,166,210,.18);--text:#e8f1ff;--muted:#8fa3c7;--cyan:#35d5ff;--blue:#6a8dff;--green:#4ade80;--amber:#fbbf24;--red:#fb7185;--violet:#a78bfa;--shadow:0 18px 55px rgba(0,0,0,.38)}\n*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;min-height:100vh;background:radial-gradient(circle at 10% 0%,rgba(53,213,255,.18),transparent 28%),radial-gradient(circle at 85% 10%,rgba(167,139,250,.18),transparent 30%),linear-gradient(135deg,#050914 0%,#07111f 52%,#0b1020 100%);color:var(--text);font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;font-size:14px}\n.shell{display:grid;grid-template-columns:260px 1fr;min-height:100vh}\n.sidebar{position:sticky;top:0;height:100vh;padding:24px 18px;border-right:1px solid var(--line);background:linear-gradient(180deg,rgba(7,17,31,.95),rgba(7,17,31,.72));backdrop-filter:blur(18px)}\n.brand{display:flex;gap:12px;align-items:center;margin-bottom:24px}\n.logo{width:42px;height:42px;border-radius:16px;background:linear-gradient(135deg,var(--cyan),var(--violet));box-shadow:0 0 30px rgba(53,213,255,.32)}\n.brand h1{font-size:18px;margin:0}\n.brand p{margin:3px 0 0;color:var(--muted);font-size:12px}\n.nav{display:grid;gap:8px}\n.nav button{width:100%;text-align:left;border:1px solid transparent;border-radius:14px;background:transparent;color:var(--muted);padding:11px 12px;cursor:pointer;font-size:14px}\n.nav button:hover,.nav button.active{color:var(--text);background:rgba(106,141,255,.12);border-color:rgba(106,141,255,.24)}\n.sidebar-footer{position:absolute;left:18px;right:18px;bottom:18px;color:var(--muted);font-size:12px}\n.main{padding:28px;min-width:0}\n.topbar{display:flex;gap:16px;align-items:flex-start;justify-content:space-between;margin-bottom:22px}\n.eyebrow{color:var(--cyan);font-weight:700;letter-spacing:.12em;text-transform:uppercase;font-size:12px}\n.title{font-size:32px;line-height:1.05;margin:6px 0 8px}\n.subtitle{color:var(--muted);margin:0;max-width:760px}\n.toolbar{display:flex;gap:10px;align-items:center;flex-wrap:wrap}\n.btn{border:1px solid rgba(53,213,255,.28);border-radius:12px;background:rgba(53,213,255,.12);color:var(--text);padding:9px 12px;cursor:pointer;font-weight:700;font-size:13px}\n.btn:hover{border-color:var(--cyan);box-shadow:0 0 0 3px rgba(53,213,255,.1)}\n.btn.danger{border-color:rgba(251,113,133,.35);background:rgba(251,113,133,.14)}\n.btn.ghost{background:rgba(145,166,210,.08);border-color:var(--line);color:var(--muted)}\n.status-dot{display:inline-flex;align-items:center;gap:7px;color:var(--muted);font-size:12px}\n.status-dot:before{content:"";width:8px;height:8px;border-radius:50%;background:var(--green);box-shadow:0 0 14px var(--green)}\n.section{display:none}.section.active{display:block}\n.bento{display:grid;grid-template-columns:repeat(12,1fr);gap:16px}\n.card{grid-column:span 4;background:linear-gradient(180deg,var(--panel2),var(--panel));border:1px solid var(--line);border-radius:22px;padding:18px;box-shadow:var(--shadow);min-width:0}\n.card.wide{grid-column:span 8}.card.full{grid-column:1/-1}\n.card h2{font-size:15px;margin:0 0 14px;display:flex;align-items:center;justify-content:space-between}\n.metric{font-size:34px;font-weight:800;letter-spacing:-.04em}\n.metric-label{color:var(--muted);font-size:12px;margin-top:4px}\n.mini{color:var(--muted);font-size:12px}\n.table-wrap{overflow:auto;max-height:520px;border-radius:14px;border:1px solid rgba(145,166,210,.12)}\ntable{width:100%;border-collapse:collapse;font-size:13px;min-width:680px}\nth,td{padding:11px 12px;text-align:left;border-bottom:1px solid rgba(145,166,210,.1);vertical-align:top}\nth{position:sticky;top:0;background:#10213f;color:#b7c7e8;font-size:12px;text-transform:uppercase;letter-spacing:.08em;z-index:1}\ntr:hover td{background:rgba(106,141,255,.07)}\n.badge{display:inline-flex;align-items:center;gap:5px;border-radius:999px;padding:3px 9px;font-size:12px;font-weight:800;border:1px solid transparent;white-space:nowrap}\n.badge-ok{background:rgba(74,222,128,.12);color:#86efac;border-color:rgba(74,222,128,.24)}\n.badge-warn{background:rgba(251,191,36,.12);color:#fde68a;border-color:rgba(251,191,36,.25)}\n.badge-err{background:rgba(251,113,133,.13);color:#fecdd3;border-color:rgba(251,113,133,.28)}\n.badge-off{background:rgba(148,163,184,.12);color:#cbd5e1;border-color:rgba(148,163,184,.18)}\n.mono{font-family:"SFMono-Regular",Consolas,"Liberation Mono",monospace}\n.truncate{max-width:360px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n.form{display:grid;grid-template-columns:repeat(6,1fr);gap:10px}\n.form input,.form select,.search{width:100%;border:1px solid var(--line);border-radius:12px;background:rgba(3,8,20,.55);color:var(--text);padding:10px;font-size:13px}\n.form input:focus,.form select:focus,.search:focus{outline:none;border-color:var(--cyan);box-shadow:0 0 0 3px rgba(53,213,255,.1)}\n.form .span2{grid-column:span 2}.form .span3{grid-column:span 3}\n.toast{position:fixed;right:22px;bottom:22px;max-width:460px;background:#0f1f3d;border:1px solid var(--line);border-radius:16px;padding:12px 14px;box-shadow:var(--shadow);display:none}\n.toast.show{display:block}\n.empty{padding:28px;color:var(--muted);text-align:center}\n.spark{height:8px;border-radius:999px;background:rgba(145,166,210,.14);overflow:hidden}\n.spark span{display:block;height:100%;background:linear-gradient(90deg,var(--cyan),var(--violet));width:0}\n.login{min-height:100vh;display:grid;place-items:center;padding:24px}\n.login-card{width:min(440px,100%);background:var(--panel);border:1px solid var(--line);border-radius:28px;padding:28px;box-shadow:var(--shadow)}\n.login-card h1{margin:0 0 8px}\n.login-card p{color:var(--muted)}\n.login-card input{width:100%;margin:14px 0;border:1px solid var(--line);border-radius:14px;background:#07111f;color:var(--text);padding:12px}\n.login-card .btn{width:100%;text-align:center;display:block}\n@media(max-width:980px){.shell{grid-template-columns:1fr}.sidebar{position:relative;height:auto}.sidebar-footer{position:static;margin-top:18px}.main{padding:18px}.card,.card.wide{grid-column:1/-1}.topbar{display:block}.toolbar{margin-top:14px}.form{grid-template-columns:1fr 1fr}.form .span2,.form .span3{grid-column:auto}}\n</style>\n</head>\n<body>\n<div class="shell">\n<aside class="sidebar">\n<div class="brand"><div class="logo"></div><div><h1>&#x674e;&#x9a6c;&#x7ba1;&#x7406;&#x9762;&#x677f;</h1><p>AI &#x8def;&#x7531;&#x8fd0;&#x7ef4;&#x4e2d;&#x5fc3;</p></div></div>\n<nav class="nav" id="nav">\n<button class="active" data-panel="overview">&#x603b;&#x89c8;</button>\n<button data-panel="traffic">&#x6d41;&#x91cf;&#x65e5;&#x5fd7;</button>\n<button data-panel="backends">&#x540e;&#x7aef;&#x7ba1;&#x7406;</button>\n<button data-panel="retrieval">&#x68c0;&#x7d22;&#x8ffd;&#x8e2a;</button>\n<button data-panel="model">&#x6a21;&#x578b;&#x4e0e;&#x8bad;&#x7ec3;</button>\n<button data-panel="agents">Agent &#x5ba1;&#x8ba1;</button>\n</nav>\n<div class="sidebar-footer"><div class="status-dot">&#x7ba1;&#x7406;&#x4f1a;&#x8bdd;&#x5df2;&#x542f;&#x7528;</div><div style="margin-top:8px"><a href="/admin/logout" style="color:var(--muted)">&#x9000;&#x51fa;&#x767b;&#x5f55;</a></div></div>\n</aside>\n<main class="main">\n<header class="topbar">\n<div><div class="eyebrow">&#x751f;&#x4ea7;&#x63a7;&#x5236;&#x53f0;</div><h1 class="title">&#x674e;&#x9a6c;&#x7ba1;&#x7406;&#x9762;&#x677f;</h1><p class="subtitle">&#x7edf;&#x4e00;&#x67e5;&#x770b;&#x8def;&#x7531;&#x5065;&#x5eb7;&#x3001;&#x8bf7;&#x6c42;&#x6d41;&#x91cf;&#x3001;&#x540e;&#x7aef;&#x80fd;&#x529b;&#x3001;&#x68c0;&#x7d22;&#x94fe;&#x8def;&#x3001;&#x6a21;&#x578b; fallback &#x4e0e; Agent &#x4efb;&#x52a1;&#x5ba1;&#x8ba1;&#x3002;</p></div>\n<div class="toolbar"><span class="status-dot" id="refresh-info">&#x7b49;&#x5f85;&#x5237;&#x65b0;</span><button class="btn" onclick="refreshAll()">&#x7acb;&#x5373;&#x5237;&#x65b0;</button></div>\n</header>\n\n<section id="panel-overview" class="section active">\n<div class="bento">\n<div class="card"><h2>&#x8bf7;&#x6c42;&#x603b;&#x91cf;</h2><div class="metric" id="s-total">0</div><div class="metric-label">Total requests</div></div>\n<div class="card"><h2>&#x5e73;&#x5747;&#x5ef6;&#x8fdf;</h2><div class="metric" id="s-avg-ms">0ms</div><div class="metric-label">Average latency</div></div>\n<div class="card"><h2>&#x8fd0;&#x884c;&#x65f6;&#x95f4;</h2><div class="metric" id="s-uptime">0s</div><div class="metric-label">Service uptime</div></div>\n<div class="card"><h2>&#x540e;&#x7aef;&#x6570;</h2><div class="metric" id="s-backends">0</div><div class="metric-label">Configured backends</div></div>\n<div class="card"><h2>&#x72ec;&#x7acb; IP</h2><div class="metric" id="s-ips">0</div><div class="metric-label">Unique clients</div></div>\n<div class="card"><h2>Fallback</h2><div class="metric" id="s-fallbacks">0</div><div class="metric-label">Fallback log entries</div></div>\n<div class="card wide"><h2>&#x540e;&#x7aef;&#x8c03;&#x7528;&#x6392;&#x884c; <span class="mini">&#x6210;&#x529f;&#x7387; / &#x5e73;&#x5747;&#x8017;&#x65f6;</span></h2><div class="table-wrap"><table><thead><tr><th>&#x540e;&#x7aef;</th><th>&#x8c03;&#x7528;</th><th>&#x6210;&#x529f;&#x7387;</th><th>&#x5e73;&#x5747; ms</th><th>&#x70ed;&#x5ea6;</th></tr></thead><tbody id="t-backends"></tbody></table></div></div>\n<div class="card"><h2>&#x610f;&#x56fe;&#x5206;&#x5e03;</h2><div class="table-wrap"><table><thead><tr><th>&#x610f;&#x56fe;</th><th>&#x6570;&#x91cf;</th><th>&#x5360;&#x6bd4;</th></tr></thead><tbody id="t-intents"></tbody></table></div></div>\n<div class="card full"><h2>IDE / &#x5165;&#x53e3;&#x5206;&#x5e03;</h2><div id="ide-bars"></div></div>\n</div>\n</section>\n\n<section id="panel-traffic" class="section"><div class="bento"><div class="card full"><h2>&#x6700;&#x8fd1;&#x8bf7;&#x6c42; <input class="search" id="log-filter" placeholder="&#x641c;&#x7d22; IP / query / backend / intent" oninput="renderLogs()"></h2><div class="table-wrap"><table><thead><tr><th>&#x65f6;&#x95f4;</th><th>IP</th><th>&#x5730;&#x533a;</th><th>IDE</th><th>Query</th><th>&#x540e;&#x7aef;</th><th>&#x610f;&#x56fe;</th><th>&#x8017;&#x65f6;</th><th>&#x72b6;&#x6001;</th></tr></thead><tbody id="t-logs"></tbody></table></div></div></div></section>\n\n<section id="panel-backends" class="section"><div class="bento">\n<div class="card full"><h2>&#x6dfb;&#x52a0;&#x540e;&#x7aef;</h2><div class="form"><input id="be-name" placeholder="name" class="span2"><input id="be-url" placeholder="url" class="span3"><input id="be-model" placeholder="model"><input id="be-key" placeholder="API Key (&#x4e0d;&#x4f1a;&#x56de;&#x663e;)" type="password" class="span2"><select id="be-fmt"><option value="openai">OpenAI</option><option value="anthropic">Anthropic</option></select><select id="be-auth"><option value="bearer">Bearer</option><option value="x-api-key">x-api-key</option></select><input id="be-tier" placeholder="tier"><button class="btn" onclick="addBackend()">&#x6dfb;&#x52a0;&#x5e76;&#x6d4b;&#x8bd5;</button></div></div>\n<div class="card full"><h2>&#x540e;&#x7aef;&#x5e93;&#x5b58; <input class="search" id="backend-filter" placeholder="&#x641c;&#x7d22; name / model / capability" oninput="renderBackends()"></h2><div class="table-wrap"><table><thead><tr><th>&#x72b6;&#x6001;</th><th>&#x540d;&#x79f0;</th><th>&#x6a21;&#x578b;</th><th>&#x683c;&#x5f0f;</th><th>&#x80fd;&#x529b;</th><th>&#x7194;&#x65ad;</th><th>&#x8c03;&#x7528;</th><th>&#x9519;&#x8bef;&#x7387;</th><th>&#x64cd;&#x4f5c;</th></tr></thead><tbody id="t-be-list"></tbody></table></div></div>\n</div></section>\n\n<section id="panel-retrieval" class="section"><div class="bento"><div class="card full"><h2>&#x68c0;&#x7d22;&#x94fe;&#x8def;&#x8ffd;&#x8e2a;</h2><div class="table-wrap"><table><thead><tr><th>&#x65f6;&#x95f4;</th><th>Query</th><th>&#x547d;&#x4e2d;</th><th>&#x7b56;&#x7565;</th><th>&#x8be6;&#x60c5;</th></tr></thead><tbody id="t-retrieval"></tbody></table></div></div></div></section>\n\n<section id="panel-model" class="section"><div class="bento">\n<div class="card"><h2>&#x8def;&#x7531;&#x6a21;&#x578b;</h2><div class="metric" id="m-name">-</div><div class="metric-label">&#x5f53;&#x524d;&#x6a21;&#x578b;</div></div>\n<div class="card"><h2>&#x51c6;&#x786e;&#x7387;</h2><div class="metric" id="m-accuracy">-</div><div class="metric-label">&#x8bad;&#x7ec3;&#x8bc4;&#x4f30;</div></div>\n<div class="card"><h2>&#x8bad;&#x7ec3;&#x6570;&#x636e;</h2><div class="metric" id="m-data">0</div><div class="metric-label">&#x6837;&#x672c;&#x6570;</div></div>\n<div class="card full"><h2>Fallback &#x6837;&#x672c;&#x4e0e;&#x8bad;&#x7ec3; <button class="btn" onclick="triggerRetrain()">&#x89e6;&#x53d1;&#x91cd;&#x8bad;</button></h2><div class="table-wrap"><table><thead><tr><th>&#x65f6;&#x95f4;</th><th>Query</th><th>&#x540e;&#x7aef;</th><th>&#x539f;&#x56e0;</th></tr></thead><tbody id="t-fallbacks"></tbody></table></div></div>\n</div></section>\n\n<section id="panel-agents" class="section"><div class="bento"><div class="card full"><h2>Agent Task Audit</h2><div class="table-wrap"><table><thead><tr><th>Task</th><th>Status</th><th>Mode</th><th>Repo</th><th>Goal</th><th>Events</th><th>Next</th></tr></thead><tbody id="t-agent-audit"></tbody></table></div></div></div></section>\n</main>\n</div>\n<div class="toast" id="toast"></div>\n<script>\nconst state={stats:null,logs:[],backends:[],model:null,traces:[],agents:[]};\nfunction authFetch(url,opts={}){opts.headers=Object.assign({\'Content-Type\':\'application/json\'},opts.headers||{});opts.credentials=\'same-origin\';return fetch(url,opts)}\nfunction esc(value){return String(value??\'\').replace(/&/g,\'&amp;\').replace(/</g,\'&lt;\').replace(/>/g,\'&gt;\').replace(/"/g,\'&quot;\').replace(/\'/g,\'&#39;\')}\nfunction escJs(value){return String(value??\'\').replace(/\\\\/g,\'\\\\\\\\\').replace(/\'/g,"\\\\\'").replace(/\\n/g,\' \')}\nfunction badge(text,type=\'off\'){return \'<span class="badge badge-\'+type+\'">\'+esc(text)+\'</span>\'}\nfunction fmtUptime(s){s=Number(s||0);if(s<60)return s+\'s\';if(s<3600)return Math.floor(s/60)+\'m \'+s%60+\'s\';var d=Math.floor(s/86400),h=Math.floor((s%86400)/3600),m=Math.floor((s%3600)/60);return (d?d+\'d \':\'\')+h+\'h \'+m+\'m\'}\nfunction toast(msg,type=\'ok\'){var el=document.getElementById(\'toast\');el.textContent=msg;el.style.borderColor=type===\'err\'?\'rgba(251,113,133,.45)\':\'rgba(53,213,255,.35)\';el.classList.add(\'show\');setTimeout(function(){el.classList.remove(\'show\')},4200)}\ndocument.querySelectorAll(\'#nav button\').forEach(function(btn){btn.addEventListener(\'click\',function(){document.querySelectorAll(\'#nav button\').forEach(function(x){x.classList.remove(\'active\')});document.querySelectorAll(\'.section\').forEach(function(x){x.classList.remove(\'active\')});btn.classList.add(\'active\');document.getElementById(\'panel-\'+btn.dataset.panel).classList.add(\'active\')})});\nasync function json(url,opts){var r=await authFetch(url,opts);if(!r.ok)throw new Error(await r.text());return r.json()}\nasync function refreshAll(){await Promise.allSettled([loadStats(),loadLogs(),loadBackends(),loadModel(),loadRetrieval(),loadAgents()]);document.getElementById(\'refresh-info\').textContent=\'刚刚刷新 \'+new Date().toLocaleTimeString()}\nasync function loadStats(){state.stats=await json(\'/admin/api/stats\');renderStats()}\nfunction renderStats(){var d=state.stats||{};document.getElementById(\'s-total\').textContent=d.total_requests??0;document.getElementById(\'s-avg-ms\').textContent=(d.avg_response_ms??0)+\'ms\';document.getElementById(\'s-uptime\').textContent=fmtUptime(d.uptime_seconds);document.getElementById(\'s-ips\').textContent=d.unique_ips??0;var calls=d.backend_calls||{};document.getElementById(\'s-backends\').textContent=Object.keys(calls).length;var tbody=document.getElementById(\'t-backends\');tbody.innerHTML=\'\';var max=Math.max(1,...Object.values(calls).map(function(x){return Number(x.count||0)}));Object.entries(calls).sort(function(a,b){return(b[1].count||0)-(a[1].count||0)}).slice(0,12).forEach(function(pair){var name=pair[0],info=pair[1];var count=Number(info.count||0),success=Number(info.success||0),rate=count?Math.round(success/count*100):0,avg=count?Math.round(Number(info.total_ms||0)/count):0;tbody.innerHTML+=\'<tr><td class="mono">\'+esc(name)+\'</td><td>\'+count+\'</td><td>\'+badge(rate+\'%\',rate>90?\'ok\':rate>60?\'warn\':\'err\')+\'</td><td>\'+avg+\'</td><td><div class="spark"><span style="width:\'+Math.round(count/max*100)+\'%"></span></div></td></tr>\'});renderIntentTable(d.intent_distribution||{});renderIdeBars(d.ide_distribution||{})}\nfunction renderIntentTable(map){var rows=Object.entries(map).sort(function(a,b){return b[1]-a[1]});var total=rows.reduce(function(a,b){return a+Number(b[1]||0)},0)||1;document.getElementById(\'t-intents\').innerHTML=rows.map(function(pair){return \'<tr><td>\'+esc(pair[0])+\'</td><td>\'+pair[1]+\'</td><td>\'+Math.round(Number(pair[1])/total*100)+\'%</td></tr>\'}).join(\'\')||\'<tr><td colspan="3" class="empty">暂无数据</td></tr>\'}\nfunction renderIdeBars(map){var rows=Object.entries(map).sort(function(a,b){return b[1]-a[1]});var max=Math.max(1,...rows.map(function(r){return Number(r[1]||0)}));document.getElementById(\'ide-bars\').innerHTML=rows.map(function(pair){return \'<div style="display:grid;grid-template-columns:160px 1fr 50px;gap:10px;align-items:center;margin:9px 0"><span>\'+esc(pair[0])+\'</span><div class="spark"><span style="width:\'+Math.round(Number(pair[1])/max*100)+\'%"></span></div><span class="mono">\'+pair[1]+\'</span></div>\'}).join(\'\')||\'<div class="empty">暂无数据</div>\'}\nasync function loadLogs(){state.logs=await json(\'/admin/api/logs\');renderLogs()}\nfunction renderLogs(){var q=(document.getElementById(\'log-filter\')?.value||\'\').toLowerCase();var rows=state.logs.filter(function(l){return JSON.stringify(l).toLowerCase().includes(q)});document.getElementById(\'t-logs\').innerHTML=rows.map(function(l){return \'<tr><td class="mini">\'+esc(l.time)+\'</td><td class="mono">\'+esc(l.ip)+\'</td><td>\'+esc(l.country)+\'</td><td>\'+esc(l.ide)+\'</td><td class="truncate" title="\'+esc(l.query||l.sys_prompt)+\'">\'+esc(l.query||l.sys_prompt)+\'</td><td class="mono">\'+esc(l.backend)+\'</td><td>\'+esc(l.intent)+\'</td><td>\'+esc(l.ms)+\'ms</td><td>\'+badge(l.success?\'成功\':\'失败\',l.success?\'ok\':\'err\')+\'</td></tr>\'}).join(\'\')||\'<tr><td colspan="9" class="empty">暂无日志</td></tr>\'}\nasync function loadBackends(){state.backends=await json(\'/admin/backends\');renderBackends()}\nfunction renderBackends(){var q=(document.getElementById(\'backend-filter\')?.value||\'\').toLowerCase();var rows=state.backends.filter(function(b){return JSON.stringify(b).toLowerCase().includes(q)});document.getElementById(\'t-be-list\').innerHTML=rows.map(function(b){var caps=(b.capabilities||[]).map(function(c){return badge(c,\'off\')}).join(\' \');var enabled=b.enabled?badge(\'启用\',\'ok\'):\'禁用\';var cb=b.state===\'open\'?badge(\'open\',\'err\'):badge(b.state||\'closed\',\'ok\');return \'<tr><td>\'+enabled+\'</td><td class="mono">\'+esc(b.name)+\'</td><td>\'+esc(b.model)+\'</td><td>\'+esc(b.format)+\'</td><td>\'+caps+\'</td><td>\'+cb+\'</td><td>\'+esc(b.total_calls||0)+\'</td><td>\'+esc(b.error_rate||\'0%\')+\'</td><td><button class="btn ghost" onclick="testBackend(\'+escJs(b.name)+\')">测试</button> <button class="btn danger" onclick="deleteBackend(\'+escJs(b.name)+\')">删除</button></td></tr>\'}).join(\'\')||\'<tr><td colspan="9" class="empty">暂无后端</td></tr>\'}\nasync function addBackend(){var body={name:v(\'be-name\'),url:v(\'be-url\'),model:v(\'be-model\'),key:v(\'be-key\'),fmt:v(\'be-fmt\'),auth:v(\'be-auth\'),tier:v(\'be-tier\')};try{var res=await json(\'/admin/backends\',{method:\'POST\',body:JSON.stringify(body)});toast(res.message||\'已添加\');await loadBackends()}catch(e){toast(\'添加失败：\'+e.message,\'err\')}}\nfunction v(id){return document.getElementById(id).value.trim()}\n);toast(\'已切换 \'+name);await loadBackends()}catch(e){toast(\'切换失败：\'+e.message,\'err\')}}\nasync function testBackend(name){try{var res=await json(\'/admin/backends/\'+encodeURIComponent(name)+\'/test\',{method:\'POST\'});toast(name+\' 测试 \'+(res.ok?\'通过\':\'失败\')+\' \'+(res.latency_ms||0)+\'ms\',res.ok?\'ok\':\'err\')}catch(e){toast(\'测试失败：\'+e.message,\'err\')}}\nasync function deleteBackend(name){if(!confirm(\'删除后端 \'+name+\' ?\'))return;try{await json(\'/admin/backends/\'+encodeURIComponent(name),{method:\'DELETE\'});toast(\'已删除 \'+name);await loadBackends()}catch(e){toast(\'删除失败：\'+e.message,\'err\')}}\nasync function loadModel(){state.model=await json(\'/admin/api/model-status\');renderModel()}\nfunction renderModel(){var d=state.model||{};document.getElementById(\'m-name\').textContent=d.model||\'-\';document.getElementById(\'m-accuracy\').textContent=d.accuracy||\'-\';document.getElementById(\'m-data\').textContent=d.data_count||0;document.getElementById(\'s-fallbacks\').textContent=d.fallback_log_count||0;var rows=d.recent_fallbacks||[];document.getElementById(\'t-fallbacks\').innerHTML=rows.slice().reverse().map(function(x){return \'<tr><td>\'+esc(x.time||x.ts||\'\')+\'</td><td class="truncate">\'+esc(x.query||x.prompt||\'\')+\'</td><td class="mono">\'+esc(x.backend||\'\')+\'</td><td>\'+esc(x.reason||x.error||\'\')+\'</td></tr>\'}).join(\'\')||\'<tr><td colspan="4" class="empty">暂无 fallback</td></tr>\'}\nasync function triggerRetrain(){if(!confirm(\'确认触发 auto_retrain.py --force ?\'))return;try{var r=await json(\'/admin/api/retrain\',{method:\'POST\'});toast(\'训练任务：\'+(r.job_id||r.status))}catch(e){toast(\'触发失败：\'+e.message,\'err\')}}\nasync function loadRetrieval(){state.traces=await json(\'/admin/api/retrieval-traces\');renderRetrieval()}\nfunction renderRetrieval(){var rows=Array.isArray(state.traces)?state.traces:[];document.getElementById(\'t-retrieval\').innerHTML=rows.map(function(t){return \'<tr><td>\'+esc(t.time||t.ts||\'\')+\'</td><td class="truncate">\'+esc(t.query||\'\')+\'</td><td>\'+esc(t.hits??t.hit_count??\'\')+\'</td><td>\'+esc(t.strategy||t.mode||\'\')+\'</td><td class="truncate" title="\'+esc(JSON.stringify(t))+\'">\'+esc(JSON.stringify(t))+\'</td></tr>\'}).join(\'\')||\'<tr><td colspan="5" class="empty">暂无检索追踪</td></tr>\'}\nasync function loadAgents(){var d=await json(\'/admin/api/agent-audit?limit=50\');state.agents=d.tasks||[];renderAgents()}\nfunction renderAgents(){document.getElementById(\'t-agent-audit\').innerHTML=state.agents.map(function(t){return \'<tr><td class="mono">\'+esc(t.task_id||t.id)+\'</td><td>\'+badge(t.status||\'-\',String(t.status).includes(\'fail\')?\'err\':String(t.status).includes(\'review\')?\'warn\':\'ok\')+\'</td><td>\'+esc(t.mode)+\'</td><td class="truncate">\'+esc(t.repo)+\'</td><td class="truncate" title="\'+esc(t.goal)+\'">\'+esc(t.goal)+\'</td><td>\'+esc(t.events_count??t.event_count??\'\')+\'</td><td>\'+esc(t.next_action||\'\')+\'</td></tr>\'}).join(\'\')||\'<tr><td colspan="7" class="empty">暂无 Agent 任务</td></tr>\'}\nrefreshAll();setInterval(refreshAll,5000);\n</script>\n</body>\n</html>'

LOGIN_HTML = '<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>&#x674e;&#x9a6c;&#x7ba1;&#x7406;&#x9762;&#x677f; - &#x767b;&#x5f55;</title><style>body{margin:0;min-height:100vh;display:grid;place-items:center;background:radial-gradient(circle at 20% 0%,rgba(53,213,255,.2),transparent 30%),#07111f;color:#e8f1ff;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.card{width:min(420px,calc(100% - 32px));padding:30px;border:1px solid rgba(145,166,210,.2);border-radius:28px;background:rgba(15,27,50,.88);box-shadow:0 18px 55px rgba(0,0,0,.38)}h1{margin:0 0 8px}.muted{color:#8fa3c7}input{width:100%;box-sizing:border-box;margin:18px 0 12px;border:1px solid rgba(145,166,210,.22);border-radius:14px;background:#07111f;color:#e8f1ff;padding:13px}button{width:100%;border:0;border-radius:14px;background:linear-gradient(135deg,#35d5ff,#a78bfa);color:#07111f;font-weight:900;padding:12px;cursor:pointer}.err{color:#fecdd3;background:rgba(251,113,133,.13);border:1px solid rgba(251,113,133,.28);padding:10px;border-radius:12px;margin-bottom:12px}</style></head><body><form class="card" method="post" action="/admin/login"><h1>&#x674e;&#x9a6c;&#x7ba1;&#x7406;&#x9762;&#x677f;</h1><p class="muted">&#x8f93;&#x5165;&#x7ba1;&#x7406;&#x5458; Token &#x8fdb;&#x5165;&#x751f;&#x4ea7;&#x63a7;&#x5236;&#x53f0;&#x3002;</p>{error}<input name="token" placeholder="Admin Token" type="password" autofocus><button type="submit">&#x767b;&#x5f55;</button></form></body></html>'

def render_admin_login(error: str = "") -> str:
    error_html = '<p class="err">' + error + '</p>' if error else ""
    return LOGIN_HTML.replace("{error}", error_html)


